import{_ as i,o as t,c as s,ao as a}from"./chunks/framework.C2uOknPB.js";const u=JSON.parse('{"title":"Limitations (v1)","description":"","frontmatter":{},"headers":[],"relativePath":"guide/limitations.md","filePath":"guide/limitations.md","lastUpdated":null}'),n={name:"guide/limitations.md"};function o(r,e,d,l,h,c){return t(),s("div",null,[...e[0]||(e[0]=[a('<h1 id="Limitations-v1" tabindex="-1">Limitations (v1) <a class="header-anchor" href="#Limitations-v1" aria-label="Permalink to &quot;Limitations (v1) {#Limitations-v1}&quot;">​</a></h1><p>ParselTongue v0.1 is built on the experimental <code>juliac --trim</code>. These are the known constraints, with the reasoning behind each.</p><h2 id="One-extension-per-Python-process" tabindex="-1">One extension per Python process <a class="header-anchor" href="#One-extension-per-Python-process" aria-label="Permalink to &quot;One extension per Python process {#One-extension-per-Python-process}&quot;">​</a></h2><p>Each wheel embeds its own copy of <code>libjulia</code>. Importing <strong>two</strong> ParselTongue extensions into the same Python process aborts the process — two Julia runtimes cannot coexist.</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> mathx     </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ok</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> strx      </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># abort: a second libjulia is loaded</span></span></code></pre></div><p>Build the functions you need to use together into a <strong>single</strong> module — and use <a href="/ParselTongue.jl/dev/examples/scientific#Submodules"><code>@pymodule pkg.sub</code></a> to split one extension&#39;s API across Python submodules (<code>pkg.linalg</code>, <code>pkg.dsp</code>, …), all backed by one image, so <code>import pkg.linalg</code> and <code>import pkg.dsp</code> coexist fine. A shared-runtime mode (one libjulia across <em>separate</em> extensions) is future work.</p><h2 id="Wheel-size-100-MB" tabindex="-1">Wheel size (~100 MB) <a class="header-anchor" href="#Wheel-size-100-MB" aria-label="Permalink to &quot;Wheel size (~100 MB) {#Wheel-size-100-MB}&quot;">​</a></h2><p>The trimmed code is tiny, but the Julia runtime&#39;s standard-library <code>__init__</code> functions (OpenBLAS, SuiteSparse, …) run at startup and dlopen their backing libraries even when your code never uses them. Those libraries must therefore be bundled. Only the system image, the LLVM JIT, and codegen (~500 MB) are excluded, since a trimmed AOT binary provably never needs them.</p><p>Shrinking the wheel further requires suppressing the unused stdlib inits — a planned optimization.</p><h2 id="Array-dtype-checking-is-width-only" tabindex="-1">Array dtype checking is width-only <a class="header-anchor" href="#Array-dtype-checking-is-width-only" aria-label="Permalink to &quot;Array dtype checking is width-only {#Array-dtype-checking-is-width-only}&quot;">​</a></h2><p>An array argument is validated by element <strong>size</strong>, not signedness or kind. A <code>float64</code> buffer passed where <code>Int64</code> is expected (both 8 bytes) is not caught and will be reinterpreted. Match dtypes carefully on the Python side.</p><h2 id="trim-:safe-rejects-dynamic-dispatch" tabindex="-1"><code>trim = :safe</code> rejects dynamic dispatch <a class="header-anchor" href="#trim-:safe-rejects-dynamic-dispatch" aria-label="Permalink to &quot;`trim = :safe` rejects dynamic dispatch {#trim-:safe-rejects-dynamic-dispatch}&quot;">​</a></h2><p>This is a feature, not a bug: type-unstable or dynamically-dispatched code in an exported path fails the build. See <a href="/ParselTongue.jl/dev/guide/building#Trim-modes">Building</a> for the <code>:unsafe_warn</code> escape hatch.</p>',13)])])}const m=i(n,[["render",o]]);export{u as __pageData,m as default};
